async getDailyStats() {
  const todayStart = new Date();
  todayStart.setUTCHours(0, 0, 0, 0);
  const todayEnd = new Date(todayStart);
  todayEnd.setUTCDate(todayEnd.getUTCDate() + 1);

  const yesterdayStart = new Date(todayStart);
  yesterdayStart.setUTCDate(yesterdayStart.getUTCDate() - 1);
  const yesterdayEnd = todayStart;

  const stats = await this.orderRepository
    .createQueryBuilder('order')
    .select([
      'SUM(CASE WHEN order.created_at >= :todayStart AND order.created_at < :todayEnd THEN order.total_amount ELSE 0 END) as ca_today',
      'COUNT(CASE WHEN order.created_at >= :todayStart AND order.created_at < :todayEnd THEN 1 END) as orders_today',
      'SUM(CASE WHEN order.created_at >= :yesterdayStart AND order.created_at < :yesterdayEnd THEN order.total_amount ELSE 0 END) as ca_yesterday',
    ])
    .where('order.status = :status', { status: 'paid' })
    .setParameters({ todayStart, todayEnd, yesterdayStart, yesterdayEnd })
    .getRawOne();

  const variation = stats.ca_yesterday > 0 
    ? ((stats.ca_today - stats.ca_yesterday) / stats.ca_yesterday) * 100 
    : 0;
  const avgCart = stats.orders_today > 0 ? stats.ca_today / stats.orders_today : 0;

  return { ca_today: stats.ca_today, ca_yesterday: stats.ca_yesterday, variation, orders_today: stats.orders_today, avg_cart: avgCart };
}
